// n8n Code node: "Extract & dedupe concurrenten"
// Workflow: Daily Competitor Watcher - Fase 1
// Extracted: 2026-05-15
// Source-of-truth: workflow.json ‚Äî wijzigingen hier moeten teruggesynct worden naar n8n.

const items = $input.all();
const now = new Date();

const isoDate = now.getFullYear() + '-' +
  String(now.getMonth() + 1).padStart(2, '0') + '-' +
  String(now.getDate()).padStart(2, '0');

const dateStr = String(now.getDate()).padStart(2, '0') + '/' +
  String(now.getMonth() + 1).padStart(2, '0') + '/' + now.getFullYear();

let countryCode = 'DE';
try {
  const searchUrl = $('Zoek-configuratie').first().json.search_url || '';
  const match = searchUrl.match(/country=([A-Z]{2})/i);
  if (match) countryCode = match[1].toUpperCase();
} catch(e) {}

// Prefer the ISO-8601 string Apify's FB Ads actor returns; only treat raw
// epoch as fallback. Raw is Unix SECONDS for this actor, not ms -- detect by
// magnitude. The explicit DD/MM/YYYY branch stays as a safety net for any
// legacy locale-formatted strings.
function parseAdStartTime(raw, formatted) {
  if (formatted && typeof formatted === 'string') {
    const t = new Date(formatted).getTime();
    if (Number.isFinite(t)) return t;
    const m = formatted.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
    if (m) {
      const [, dd, mm, yyyy] = m;
      const t2 = new Date(Number(yyyy), Number(mm) - 1, Number(dd)).getTime();
      if (Number.isFinite(t2)) return t2;
    }
  }
  if (typeof raw === 'number' && Number.isFinite(raw)) {
    // 1e11 ms = year 1973; anything smaller is almost certainly seconds.
    return raw < 1e11 ? raw * 1000 : raw;
  }
  if (raw) {
    const t = new Date(raw).getTime();
    if (Number.isFinite(t)) return t;
  }
  return NaN;
}

function extractDomain(urls) {
  for (const u of urls) {
    if (!u) continue;
    try {
      const host = new URL(u).hostname.replace(/^www\./, '').toLowerCase();
      if (host && !host.includes('facebook.com') && !host.includes('fb.com') && !host.includes('instagram.com')) {
        return host;
      }
    } catch(e) {}
  }
  return '';
}

const storeMap = new Map();

items.forEach(item => {
  const ad = item.json;
  if (!ad || !ad.snapshot || !ad.snapshot.pageName) return;
  const snap = ad.snapshot;
  const storeName = snap.pageName;

  // Dedup-key priority: pageId > domain+name > name. Prefix preserves
  // the chosen strategy so duplicates can be audited from the sheet.
  const pageId = snap.pageId || ad.pageId || '';
  const websiteDomain = extractDomain([
    snap.linkUrl, snap.caption, ad.link_url, snap.cta_link, snap.page_profile_uri,
  ]);
  let dedupKey;
  if (pageId) {
    dedupKey = 'pid:' + pageId;
  } else if (websiteDomain) {
    dedupKey = 'dom:' + websiteDomain + '|' + storeName.toLowerCase();
  } else {
    dedupKey = 'name:' + storeName.toLowerCase();
  }

  const startTime = parseAdStartTime(ad.startDate, ad.startDateFormatted);
  const daysActive = Number.isFinite(startTime)
    ? Math.round((now.getTime() - startTime) / (1000 * 60 * 60 * 24))
    : null;

  if (!storeMap.has(dedupKey)) {
    storeMap.set(dedupKey, {
      dedupKey,
      storeName,
      websiteDomain,
      pageId,
      pageProfileUri: snap.pageProfileUri || '',
      adCount: 0,
      maxDaysActive: 0,
      langdraaierCount: 0,
      datesParseFailed: 0,
    });
  }
  const store = storeMap.get(dedupKey);
  store.adCount += 1;
  if (websiteDomain && !store.websiteDomain) store.websiteDomain = websiteDomain;
  if (daysActive === null) {
    store.datesParseFailed += 1;
  } else {
    if (daysActive > store.maxDaysActive) store.maxDaysActive = daysActive;
    if (daysActive > 30) store.langdraaierCount += 1;
  }
});

// Tier classification rules. Hard skip removes pure noise; rest is sorted A->B->C->RISING by score desc.
function classifyTier(adCount, maxDaysActive) {
  if (adCount < 3 && maxDaysActive < 7) return 'SKIP';
  if (adCount >= 30 || maxDaysActive >= 90) return 'A';
  if (adCount >= 15 || maxDaysActive >= 30) return 'B';
  if (adCount >= 10 || maxDaysActive >= 14) return 'C';
  if ((adCount >= 3 && maxDaysActive >= 7) || (maxDaysActive >= 21 && adCount >= 1)) {
    return 'RISING';
  }
  return 'SKIP';
}

function tierLabel(tier) {
  if (tier === 'A') return 'A -- KILLER';
  if (tier === 'B') return 'B -- PROMISING';
  if (tier === 'C') return 'C -- WATCH';
  if (tier === 'RISING') return 'RISING STAR';
  return 'SKIP';
}

const tierOrder = { 'A': 1, 'B': 2, 'C': 3, 'RISING': 4 };

const intermediate = [];
for (const [, data] of storeMap) {
  const tier = classifyTier(data.adCount, data.maxDaysActive);
  if (tier === 'SKIP') continue;
  const score = Math.round(data.adCount + data.maxDaysActive * 0.5);
  intermediate.push({ data, tier, score });
}

intermediate.sort((a, b) => {
  const ta = tierOrder[a.tier] || 99;
  const tb = tierOrder[b.tier] || 99;
  if (ta !== tb) return ta - tb;
  return b.score - a.score;
});

const output = [];
for (const { data, tier, score } of intermediate) {
  let storeUrl = data.websiteDomain;
  if (storeUrl && !storeUrl.startsWith('http')) {
    storeUrl = 'https://' + storeUrl;
  }

  let adLibUrl = '';
  if (data.pageId) {
    adLibUrl = 'https://www.facebook.com/ads/library/?active_status=active&ad_type=all&country=' + countryCode + '&view_all_page_id=' + data.pageId;
  } else if (data.pageProfileUri) {
    adLibUrl = data.pageProfileUri;
  }

  let activityLabel;
  if (data.adCount < 20) {
    activityLabel = 'LAGE ACTIVITEIT (<20 ADS)';
  } else if (data.adCount < 30) {
    activityLabel = 'GEMIDDELDE ACTIVITEIT (20-29 ADS)';
  } else {
    activityLabel = 'HOGE ACTIVITEIT (30+ ADS)';
  }

  const noteParts = [];
  if (data.langdraaierCount > 0) {
    noteParts.push(data.langdraaierCount + ' langdraaier(s), max ' + data.maxDaysActive + ' dagen');
  }
  if (data.datesParseFailed > 0) {
    noteParts.push(data.datesParseFailed + ' ad(s) zonder bruikbare datum');
  }

  const sheetDedupKey = countryCode + '|' + data.dedupKey; // FIX 12-07-2026: datum uit dedup-sleutel — één rij per store, dagelijkse update i.p.v. duplicaat

  output.push({
    json: {
      'DEDUP KEY': sheetDedupKey,
      'STORE URL': storeUrl,
      'AD LIBR. URL': adLibUrl,
      'DATUM GEVONDEN': dateStr,
        'ONDERZOEKSDATUM': isoDate,
      'AANTAL PRODUCTEN': '',
      'ACTIEVE ADS': data.adCount,
      'LAATSTE UPDATE': activityLabel,
      'STORE THEMA': '',
      'NOTE': noteParts.join(' | '),
      'STORE NAAM': data.storeName,
      'TIER': tierLabel(tier),
      'SCORE': score,
    },
  });
}

return output;
